    'star', '#10B981', '#EDFAF5',
    'Возврат к спорту по силе, движению и сроку',
    '["Ежедневная растяжка и силовая работа 3 раза в неделю","Постепенный возврат к работе с весами","Движения вашего вида спорта — по согласованию с хирургом"]',
    '["Нагрузка не должна вызывать боль и отёк"]',
    '["Не пропускайте поддерживающие упражнения даже на хорошем самочувствии","Возвращайтесь к нагрузке постепенно, без рывков","Прислушивайтесь к уверенности — психологическая готовность так же важна, как физическая"]',
    '["Боль или слабость при возврате к нагрузке — стоп и к куратору"]',
    '[{"q":"Почему возврат к спорту так нескоро?","a":"Массивный разрыв заживает медленно и имеет высокий риск повторного разрыва. Для контактного спорта и тяжёлого труда нужно не меньше 9 месяцев. Хорошая сила при недостаточном сроке всё равно опасна."},{"q":"Кто решает, что я готов?","a":"Решение принимается вместе с куратором и обязательно согласуется письменно с хирургом. Учитывают и силу, и качество движений, и срок после операции."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_rcr_massive
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) пустая — не включена. У протокола нет measurement-критериев:
--    вся боль идёт как self_report, числовые пороги (градусы/недели/месяцы/сила) — instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (максимальная защита → пассивные движения)
  (1, 'wound_healed_p1',        'Рана зажила без признаков инфекции — подтверждает хирург',                                  'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'immobilization_ok_p1',   'Режим иммобилизации и техника безопасности соблюдаются',                                    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'time_6wk_p1',            'Прошло не менее 6 недель от операции (нижняя граница; до 8 недель при плохой ткани)',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'pain_controlled_p1',     'Боль и воспаление под контролем',                                                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль и воспаление под контролем — нет резкой неконтролируемой боли в покое?', 'Сравните с тем, как было в первые дни после операции', 40::smallint, TRUE),
  (1, 'no_repair_failure_p1',   'Нет признаков несостоятельности шва при осмотре',                                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (пассивные движения → активные движения)
  (2, 'passive_elevation_p2',   'Пассивный подъём руки достигает не менее 100–120°',                                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_er_p2',          'Пассивная наружная ротация при руке у тела достигает не менее 25–45°',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'passive_abduction_p2',   'Пассивное отведение руки в сторону достигает не менее 90°',                                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'healing_ok_p2',          'Адекватное заживление, предосторожности соблюдаются',                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'pain_controlled_p2',     'Боль и воспаление под контролем',                                                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль и воспаление под контролем?', 'Оцените по последним дням занятий', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (активные движения → начальное укрепление)
  (3, 'passive_elev_140_p3',    'Пассивный подъём руки больше 140°',                                                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'active_flexion_120_p3',  'Активный (самостоятельный) подъём руки больше 120° без перекосов',                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'er_normal_p3',           'Наружная ротация при руке у тела близка к норме',                                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'scapula_position_p3',    'Лопатка правильно расположена в покое и при движении',                                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'daily_tasks_p3',         'Получается выполнять лёгкие дела ниже уровня плеча без боли',                                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять лёгкие задачи ниже уровня плеча без боли?', 'Например, поесть, причесаться, набрать текст', 50::smallint, FALSE),

  -- Фаза 4 → Фаза 5 (начальное укрепление → продвинутое укрепление)
  (4, 'full_rom_p4',            'Полный объём движений во всех направлениях с правильной техникой',                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'no_pain_adl_p4',         'Нет боли при повседневной активности и упражнениях',                                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Нет боли при повседневной активности и упражнениях?', 'Оцените по последней неделе занятий', 20::smallint, TRUE),
  (4, 'no_scapula_compensation_p4', 'Нет перекосов и компенсаций в работе лопатки при нагрузке',                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),

  -- Фаза 5 → Фаза 6 (продвинутое укрепление → возврат к спорту)
  (5, 'full_painless_rom_p5',   'Полный безболезненный объём движений без компенсаций',                                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'strength_4plus_p5',      'Сила плеча хорошая без боли (ориентир — не ниже 4+ из 5 при осмотре)',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (5, 'scapula_kinematics_p5',  'Лопатка и плечо двигаются слаженно',                                                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (5, 'basic_tasks_painfree_p5','Базовые задачи и упражнения выполняются без боли',                                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Базовые задачи и упражнения получается выполнять без боли?', 'Оцените по последним тренировкам', 40::smallint, TRUE),

  -- Фаза 6 → завершение (возврат к спорту / функции)
  (6, 'strength_85_90_p6',      'Сила оперированного плеча не менее 85–90% от здоровой стороны',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (6, 'time_9mo_p6',            'Прошло не менее 9 месяцев для контактного спорта и тяжёлого труда (для отдыха — обычно не менее 4–6 месяцев)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (6, 'sport_confidence_p6',    'Уверенное безболевое выполнение движений своего вида спорта',                                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверенно выполняете движения вашего вида спорта без боли и страха?', 'Оцените по пробным спорт-специфическим движениям', 30::smallint, TRUE),
  (6, 'no_painful_arc_p6',      'Нет болезненной дуги при активном отведении руки и нет компенсаций',                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (6, 'surgeon_clearance_p6',   'Возврат к спорту письменно согласован с хирургом',                                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_rcr_massive' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
